  }

  function confirmDelete(book: Book) {
    Alert.alert('Delete book', `Remove "${book.title}" from the catalogue?`, [
      {
        text: 'Cancel',
        style: 'cancel',
      },
      {
        text: 'Delete',
        style: 'destructive',
