function normalizeBooksById(rawBooks: Book[]) {
  const uniqueBooks = new Map<string, Book>();

  rawBooks.forEach((book) => {
    if (!uniqueBooks.has(book.id)) {
      uniqueBooks.set(book.id, book);
    }
  });

  return Array.from(uniqueBooks.values());
}

